sql:
SELECT * 
FROM training 
WHERE employee_id = 1 AND training_date > '2022-01-01';

SELECT a.employee_id, a.award_name, b.benefit_id
FROM awards a
INNER JOIN employee_benefits b ON a.employee_id = b.employee_id;

SELECT first_name, last_name
FROM employees
WHERE employee_id IN (SELECT employee_id FROM supervisors);

SELECT COUNT(employee_id) AS number_of_employees
FROM skills
WHERE skill_name = 'Leadership';

external_knowledge:
- "stars still shining brightly in their current roles" refers to employees who are currently assigned to a department with no end date;
- "have been acknowledged with accolades" means these employees have received awards;
- An "award" signifies recognition for their contributions or achievements in the workplace.

sql:
SELECT e.first_name, e.last_name
FROM employees e
JOIN disciplinary_actions da ON e.employee_id = da.employee_id;

SELECT trainer, COUNT(training_id) AS Number_of_Sessions
FROM training
GROUP BY trainer;
